import type Accessor from "../../core/Accessor.js";

/** @since 5.0 */
export interface LayerListVisibleElementsProperties extends Partial<Pick<LayerListVisibleElements, "catalogLayerList" | "closeButton" | "collapseButton" | "errors" | "filter" | "flow" | "heading" | "statusIndicators" | "temporaryLayerIndicators">> {}

/**
 * The visible elements that are displayed within the layer list.
 * This provides the ability to turn on/off individual elements of the layer list.
 */
export default class LayerListVisibleElements extends Accessor {
  constructor(properties?: LayerListVisibleElementsProperties);
  /**
   * Indicates whether to display the [LayerList.catalogLayerList](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#catalogLayerList).
   *
   * @default true
   * @since 5.0
   */
  accessor catalogLayerList: boolean;
  /**
   * Indicates whether to display a close button in the header.
   *
   * @default false
   * @since 5.0
   */
  accessor closeButton: boolean;
  /**
   * Indicates whether to display a collapse button in the header.
   *
   * @default false
   * @since 5.0
   */
  accessor collapseButton: boolean;
  /**
   * Indicates whether to display layers with load errors.
   *
   * @default false
   * @since 5.0
   */
  accessor errors: boolean;
  /**
   * Indicates whether to display a filter input box when then number of list items is equal to or greater than the value set in [LayerList.minFilterItems](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#minFilterItems), allowing users to filter layers by their title.
   *
   * @default false
   * @since 5.0
   */
  accessor filter: boolean;
  /**
   * Indicates whether the layer list should be shown within its built-in [flow component](https://developers.arcgis.com/calcite-design-system/components/flow/) or if the flow component should be excluded. The layer list will be displayed within its original flow component if set to `true`. The flow component will be omitted from the layer list if set to `false`. To place the layer list into an existing Calcite flow component, set this property to `false`.
   *
   * @default true
   * @since 5.0
   */
  accessor flow: boolean;
  /**
   * Indicates whether to display the layer list heading. The heading text is "Layer List". The heading level can be set with the [LayerList.headingLevel](https://developers.arcgis.com/javascript/latest/references/core/widgets/LayerList/#headingLevel).
   *
   * @default false
   * @since 5.0
   */
  accessor heading: boolean;
  /**
   * Indicates whether the status indicators will be displayed.
   *
   * @default true
   * @since 5.0
   */
  accessor statusIndicators: boolean;
  /**
   * Indicates whether temporary layer indicators will be displayed for layers with [Layer.persistenceEnabled](https://developers.arcgis.com/javascript/latest/references/core/layers/Layer/#persistenceEnabled) set to `false`. A [temporary icon](https://developers.arcgis.com/calcite-design-system/icons/?icon=temporary&library=Calcite%20UI&query=temporary) will be displayed on the near side of the layer title.
   *
   * @default false
   * @since 5.0
   */
  accessor temporaryLayerIndicators: boolean;
}